GO



SELECT 'Student batch insert seed is ready.' AS Result;
SELECT COUNT(*) AS TotalUsers
FROM dbo.Users
WHERE UserID LIKE 'US[0-9][0-9][0-9]';
SELECT COUNT(*) AS TotalStudents
FROM dbo.Students
WHERE StudentID LIKE 'SV[0-9][0-9][0-9]';
SELECT TOP 20
    U.UserID,
    U.StudentID,
    U.Name,
    U.Username,
    U.[Password],
    S.Major,
    U.GPA,
    U.TuitionOwed
FROM dbo.Users U
INNER JOIN dbo.Students S ON S.StudentID = U.StudentID
ORDER BY U.StudentID;
